// ─── CURSOR ────


function Cursor() {
  const mouse = useMouse();
  const [trail, setTrail] = useState({ x: 0, y: 0 });
  const tr = useRef({ x: 0, y: 0 });
  useEffect(() => {
    let id;
    const loop = () => {
      tr.current.x += (mouse.x - tr.current.x) * 0.12;
      tr.current.y += (mouse.y - tr.current.y) * 0.12;
      setTrail({ x: tr.current.x, y: tr.current.y });
      id = requestAnimationFrame(loop);
    };
    id = requestAnimationFrame(loop);
    return () => cancelAnimationFrame(id);
  }, [mouse]);
  return (<>
    <div style={{ position: "fixed", pointerEvents: "none", zIndex: 9999, left: mouse.x - 5, top: mouse.y - 5, width: 10, height: 10, borderRadius: "50%", background: "#6EE7B7", mixBlendMode: "difference" }} />
    <div style={{ position: "fixed", pointerEvents: "none", zIndex: 9998, left: trail.x - 20, top: trail.y - 20, width: 40, height: 40, borderRadius: "50%", border: "1px solid rgba(110,231,183,0.45)" }} />
  </>);
}

