function Footer({ dark }) {
  return (
    <footer style={{ borderTop: `1px solid ${dark ? "rgba(255,255,255,0.05)" : "rgba(0,0,0,0.08)"}`, padding: "28px 28px", background: dark ? "#08080C" : "#f5f5f0" }}>
      <div style={{ maxWidth: 1160, margin: "0 auto", display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 12 }}>
        <img src={LOGO_SRC} alt="VY Logo" style={{ height: 40, width: 40, objectFit: "contain", filter: "drop-shadow(0 0 6px rgba(212,175,55,0.4))" }} />
        <span style={{ fontFamily: "Space Grotesk,sans-serif", fontSize: 12, color: dark ? "rgba(255,255,255,0.2)" : "rgba(0,0,0,0.3)" }}>© {new Date().getFullYear()} Vikas Yadav · Frontend Developer</span>
        <span style={{ fontFamily: "Space Grotesk,sans-serif", fontSize: 12, color: dark ? "rgba(255,255,255,0.2)" : "rgba(0,0,0,0.3)" }}>React.js · Tailwind CSS · ❤️</span>
      </div>
    </footer>
  );
}

// ─── LABEL ──────


function Label({ children, centered, dark }) {
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 10, justifyContent: centered ? "center" : "flex-start" }}>
      <span style={{ display: "block", width: 20, height: 1.5, background: "#6EE7B7", borderRadius: 99 }} />
      <span style={{ fontFamily: "Space Grotesk,sans-serif", fontSize: 10, color: "#6EE7B7", letterSpacing: "0.16em", fontWeight: 700 }}>{children}</span>
      <span style={{ display: "block", width: 60, height: 1, background: "rgba(110,231,183,0.12)" }} />
    </div>
  );
}

// ─── GLOBAL CSS ───────────────────────────────────────────────────────────
const CSS = `
  @import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@300;400;500;600;700&display=swap');
  *, *::before, *::after { box-sizing: border-box; }
  html { scroll-behavior: smooth; }
  body { margin: 0; background: #08080C; cursor: none; }
  @keyframes blink    { 0%,100%{opacity:1;} 50%{opacity:0;} }
  @keyframes scrollPulse { 0%,100%{opacity:0;transform:scaleY(0.3);} 50%{opacity:1;transform:scaleY(1);} }
  @keyframes gradShift{ 0%{background-position:0% 50%;} 100%{background-position:100% 50%;} }
  @keyframes spin     { from{transform:rotate(0deg);} to{transform:rotate(360deg);} }
  @keyframes float    { 0%,100%{transform:translateY(0);} 50%{transform:translateY(-8px);} }
  @keyframes logoPulse{ 0%,100%{opacity:1;transform:scale(1);} 50%{opacity:0.6;transform:scale(1.06);} }
  .nav-m { display: none !important; }

  /* ── ADDED: Resume & animation keyframes ── */
  @keyframes resumeOrb   { 0%{transform:translate(-50%,-50%) scale(1);} 100%{transform:translate(-50%,-50%) scale(1.3);} }
  @keyframes rippleFade  { 0%{opacity:0.5;transform:scale(1);} 100%{opacity:0;transform:scale(1.6);} }
  @keyframes downloadBounce { 0%,100%{transform:translateY(0);} 50%{transform:translateY(3px);} }
  @keyframes floatIcon   { 0%,100%{transform:translateY(0) rotate(0deg);} 50%{transform:translateY(-6px) rotate(3deg);} }
  @keyframes modalIn     { from{opacity:0;} to{opacity:1;} }
  @keyframes modalSlideUp{ from{opacity:0;transform:translateY(30px) scale(0.97);} to{opacity:1;transform:none;} }

  /* ── ADDED: Navbar slide-down entrance ── */
  @keyframes navSlideDown { from{transform:translateY(-100%);opacity:0;} to{transform:none;opacity:1;} }
  nav { animation: navSlideDown 0.7s cubic-bezier(0.16,1,0.3,1) 0.3s both; }

  /* ── ADDED: Smooth scrolling upgrade ── */
  html { scroll-behavior: smooth; scroll-padding-top: 80px; }

  /* ── ADDED: Resume grid responsive ── */
  .resume-grid { grid-template-columns: repeat(2,1fr) !important; }
  .resume-preview-card { flex-direction: row !important; }

  /* ── ADDED: Global link & button hover glow ── */
  a, button { -webkit-tap-highlight-color: transparent; }

  /* ── ADDED: Section fade-in via class (scroll reveal) ── */
  .section-reveal { opacity: 0; transform: translateY(32px); transition: opacity 0.85s cubic-bezier(0.16,1,0.3,1), transform 0.85s cubic-bezier(0.16,1,0.3,1); }
  .section-reveal.revealed { opacity: 1; transform: none; }

  /* ── ADDED: Floating background particles ── */
  @keyframes particleDrift {
    0%   { transform: translateY(0px) translateX(0px) rotate(0deg); opacity: 0.15; }
    33%  { transform: translateY(-18px) translateX(8px) rotate(120deg); opacity: 0.25; }
    66%  { transform: translateY(-8px) translateX(-6px) rotate(240deg); opacity: 0.18; }
    100% { transform: translateY(0px) translateX(0px) rotate(360deg); opacity: 0.15; }
  }

  /* ── ADDED: Skill bar glow pulse ── */
  @keyframes barGlowPulse { 0%,100%{filter:brightness(1);} 50%{filter:brightness(1.25) drop-shadow(0 0 6px currentColor);} }

  /* ── ADDED: Hero section animated gradient shimmer ── */
  @keyframes heroShimmer {
    0%   { background-position: 0% 50%; }
    50%  { background-position: 100% 50%; }
    100% { background-position: 0% 50%; }
  }

  /* ── ADDED: Project card entrance stagger ── */
  @keyframes cardEntrance { from{opacity:0;transform:translateY(40px);} to{opacity:1;transform:none;} }

  /* ── TABLET RESUME responsive ── */
  @media (max-width: 900px) {
    .resume-grid { grid-template-columns: 1fr !important; }
  }
  @media (max-width: 600px) {
    .resume-preview-card { flex-direction: column !important; align-items: flex-start !important; }
    #resume { padding-top: 70px !important; padding-bottom: 70px !important; padding-left: 18px !important; padding-right: 18px !important; }
  }

  /* ── TABLET ≤ 900px ── */
  @media (max-width: 900px) {
    .nav-d            { display: none !important; }
    .nav-m            { display: block !important; }
    .hero-grid        { grid-template-columns: 1fr !important; gap: 40px !important; }
    .hero-photo-wrap  { order: -1; }
    .split-grid       { grid-template-columns: 1fr !important; gap: 40px !important; }
    .edu-grid         { grid-template-columns: 1fr !important; }
    .proj-row         { grid-template-columns: 1fr !important; gap: 14px !important; }
    .stats-grid       { grid-template-columns: 1fr 1fr !important; }
    body              { cursor: auto; }
  }

  /* ── MOBILE ≤ 600px ── */
  @media (max-width: 600px) {
    /* Sections */
    #hero,#about,#skills,#projects,#education,#contact {
      padding-top: 70px !important;
      padding-bottom: 70px !important;
      padding-left: 18px !important;
      padding-right: 18px !important;
    }
    #hero { padding-top: 0 !important; min-height: 100svh !important; }

    /* Navbar */
    nav > div:first-child { height: 60px !important; padding: 0 18px !important; }

    /* Hero layout */
    .hero-grid        { padding-top: 0 !important; gap: 28px !important; align-items: center !important; }
    .hero-photo-wrap  { order: -1; margin-top: 80px; }

    /* Hero photo — portrait card on mobile */
    .hero-photo-wrap > div:nth-child(4) {
      width: min(260px, 75vw) !important;
      height: min(320px, 92vw) !important;
      border-radius: 16px !important;
    }

    /* Hide orbit rings & floating badges on mobile */
    .hero-photo-wrap > div:nth-child(1),
    .hero-photo-wrap > div:nth-child(2),
    .hero-photo-wrap > div:nth-child(5),
    .hero-photo-wrap > div:nth-child(6),
    .hero-photo-wrap > div:nth-child(7) { display: none !important; }

    /* CTAs stack vertically */
    .hero-ctas        { flex-direction: column !important; width: 100% !important; }
    .hero-ctas > *    { width: 100% !important; text-align: center !important; box-sizing: border-box !important; }

    /* Stats grid 2 cols */
    .stats-grid       { grid-template-columns: 1fr 1fr !important; gap: 10px !important; margin-top: 24px !important; }
    .stats-grid > div { padding: 14px 10px !important; }

    /* About cards 2 cols */
    .about-cards      { grid-template-columns: 1fr 1fr !important; gap: 10px !important; }

    /* Skill bar label narrower */
    .skill-row        { gap: 10px !important; }
    .skill-label      { min-width: 100px !important; font-size: 11px !important; }
    .skill-pct        { min-width: 32px !important; font-size: 11px !important; }

    /* Project cards — hide number col */
    .proj-row         { grid-template-columns: 1fr auto !important; padding: 20px 18px !important; }
    .proj-num         { display: none !important; }

    /* Edu/cert cards */
    .edu-grid         { gap: 16px !important; }
    .cert-card        { padding: 16px 18px !important; }

    /* Contact */
    .contact-links    { flex-direction: column !important; }
    .contact-links > a{ width: 100% !important; text-align: center !important; box-sizing: border-box !important; }

    /* Footer */
    footer > div      { flex-direction: column !important; text-align: center !important; gap: 6px !important; }

    /* Theme toggle */
    .theme-toggle-btn { bottom: 16px !important; right: 16px !important; width: 44px !important; height: 44px !important; }
  }

  /* ── SMALL PHONES ≤ 380px ── */
  @media (max-width: 380px) {
    .about-cards      { grid-template-columns: 1fr !important; }
    .stats-grid       { grid-template-columns: 1fr 1fr !important; gap: 8px !important; }
    .hero-photo-wrap > div:nth-child(4) {
      width: 220px !important;
      height: 270px !important;
    }
  }
`;

// ─── APP ──────────


export default function App() {
  const [dark, setDark] = useState(true);
  const [loaded, setLoaded] = useState(false);
  return (<>
    <style>{CSS}</style>
    {!loaded && <Loader onDone={() => setLoaded(true)} />}
    <div style={{ background: dark ? "#08080C" : "#f5f5f0", minHeight: "100vh", color: dark ? "#fff" : "#0a0a0a", opacity: loaded ? 1 : 0, transition: "opacity 0.5s ease" }}>
      <ScrollProgress />
      <Cursor />
      <ThemeToggle dark={dark} toggle={() => setDark(d => !d)} />
      <Navbar dark={dark} toggleTheme={() => setDark(d => !d)} />
      <Hero dark={dark} />
      <About dark={dark} />
      <Skills dark={dark} />
      <Projects dark={dark} />
      <Education dark={dark} />
      {/* ── ADDED: Resume section ── */}
      <Resume dark={dark} />
      <Contact dark={dark} />
      <Footer dark={dark} />
    </div>
  </>);
}
